class ProductionLoggingSystem private constructor(private val context: Context) {

    companion object {
        @Volatile
        private var instance: ProductionLoggingSystem? = null

        fun initialize(context: Context): ProductionLoggingSystem {
            return instance ?: synchronized(this) {
                instance ?: ProductionLoggingSystem(context.applicationContext).also {
                    instance = it
                    it.setupTimber()
                }
            }
        }

        fun getInstance(): ProductionLoggingSystem {
            return instance ?: throw IllegalStateException("ProductionLoggingSystem not initialized")
        }
    }

    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.getDefault())
    private val logFile: File by lazy {
        File(context.getExternalFilesDir(null), "production_logs.txt")
    }

    private fun setupTimber() {
        Timber.plant(object : Timber.DebugTree() {
            override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
                super.log(priority, tag, message, t)
                writeToFile(priority, tag, message, t)
            }
        })
        
        Timber.plant(FileLoggingTree(logFile))
    }

    private fun writeToFile(priority: Int, tag: String?, message: String, t: Throwable?) {
        try {
            val timestamp = dateFormat.format(Date())
            val priorityStr = when (priority) {
                Log.VERBOSE -> "V"
                Log.DEBUG -> "D"
                Log.INFO -> "I"
                Log.WARN -> "W"
                Log.ERROR -> "E"
                Log.ASSERT -> "A"
                else -> "?"
            }
            
            val logEntry = StringBuilder()
            logEntry.append("[$timestamp] $priorityStr/${tag ?: "Unknown"}: $message\n")
            
            if (t != null) {
                val sw = StringWriter()
                val pw = PrintWriter(sw)
                t.printStackTrace(pw)
                logEntry.append("Exception: ${sw.toString()}\n")
            }
            
            FileWriter(logFile, true).use { writer ->
                writer.append(logEntry.toString())
            }
        } catch (e: Exception) {
            Log.e("ProductionLoggingSystem", "Failed to write to log file", e)
        }
    }

    fun logAuthenticationAttempt(
        username: String,
