        method: String,
        ipAddress: String? = null,
        deviceInfo: String? = null,
        errorMessage: String? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "AUTHENTICATION")
            put("timestamp", dateFormat.format(Date()))
            put("username", username)
            put("success", success)
            put("method", method)
            put("ip_address", ipAddress ?: "unknown")
            put("device_info", deviceInfo ?: getDeviceInfo())
            if (!success && errorMessage != null) {
                put("error_message", errorMessage)
            }
        }

        if (success) {
            Timber.i("AUTH_SUCCESS: %s", logData.toString(2))
        } else {
            Timber.w("AUTH_FAILED: %s", logData.toString(2))
        }
    }

    fun logDatabaseQuery(
        query: String,
        parameters: List<Any?>? = null,
        executionTimeMs: Long? = null,
