        error: Throwable? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "DATABASE_QUERY")
            put("timestamp", dateFormat.format(Date()))
            put("query", query)
            
            if (parameters != null && parameters.isNotEmpty()) {
                put("parameters", JSONArray(parameters.map { it?.toString() ?: "null" }))
            }
            
            if (executionTimeMs != null) {
                put("execution_time_ms", executionTimeMs)
            }
            
            if (rowsAffected != null) {
                put("rows_affected", rowsAffected)
            }
            
            if (error != null) {
                put("error", error.message)
                put("error_stack", getStackTraceString(error))
            }
        }

        if (error != null) {
            Timber.e(error, "DB_QUERY_ERROR: %s", logData.toString(2))
        } else {
            Timber.v("DB_QUERY: %s", logData.toString(2))
        }
    }

    fun logApiRequest(
        method: String,
        url: String,
        headers: Map<String, String>,
        requestBody: String? = null,
        responseCode: Int? = null,
        responseBody: String? = null,
        responseHeaders: Map<String, String>? = null,
        durationMs: Long? = null,
        error: Throwable? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "API_REQUEST")
            put("timestamp", dateFormat.format(Date()))
            put("method", method)
            put("url", url)
            put("request_headers", JSONObject(sanitizeHeaders(headers)))
            
            if (requestBody != null) {
                put("request_body", sanitizeBody(requestBody))
            }
            
            if (responseCode != null) {
                put("response_code", responseCode)
            }
            
            if (responseBody != null) {
                put("response_body", sanitizeBody(responseBody))
            }
            
            if (responseHeaders != null) {
                put("response_headers", JSONObject(sanitizeHeaders(responseHeaders)))
            }
            
            if (durationMs != null) {
                put("duration_ms", durationMs)
            }
            
            if (error != null) {
                put("error", error.message)
                put("error_stack", getStackTraceString(error))
            }
        }

        if (error != null) {
            Timber.e(error, "API_REQUEST_ERROR: %s", logData.toString(2))
        } else if (responseCode != null && responseCode >= 400) {
            Timber.w("API_REQUEST_FAILED: %s", logData.toString(2))
        } else {
            Timber.d("API_REQUEST: %s", logData.toString(2))
        }
    }

    fun logException(
        exception: Throwable,
        context: String? = null,
        additionalData: Map<String, Any?>? = null,
        isFatal: Boolean = false
    ) {
        val logData = JSONObject().apply {
            put("event_type", "EXCEPTION")
            put("timestamp", dateFormat.format(Date()))
            put("exception_type", exception.javaClass.simpleName)
            put("message", exception.message)
            put("stack_trace", getStackTraceString(exception))
            put("is_fatal", isFatal)
            
            if (context != null) {
                put("context", context)
            }
            
            if (additionalData != null) {
                put("additional_data", JSONObject(additionalData))
            }
            
            put("device_info", getDeviceInfo())
        }

        if (isFatal) {
            Timber.wtf(exception, "FATAL_EXCEPTION: %s", logData.toString(2))
        } else {
            Timber.e(exception, "EXCEPTION: %s", logData.toString(2))
        }
    }

