            put("event_type", "USER_ACTION")
            put("timestamp", dateFormat.format(Date()))
            put("action", action)
            put("screen", screen)
            
            if (additionalData != null) {
                put("additional_data", JSONObject(additionalData))
            }
        }

        Timber.i("USER_ACTION: %s", logData.toString(2))
