            }
        }

        Timber.d("PERFORMANCE: %s", logData.toString(2))
    }

    private fun sanitizeHeaders(headers: Map<String, String>): Map<String, String> {
        val sensitiveKeys = setOf("authorization", "cookie", "api-key", "token", "password")
        return headers.mapValues { (key, value) ->
            if (sensitiveKeys.contains(key.lowercase())) {
                "***REDACTED***"
            } else {
                value
            }
        }
    }

    private fun sanitizeBody(body: String): String {
        return try {
            val json = JSONObject(body)
            val sensitiveKeys = setOf("password", "token", "api_key", "secret", "creditCard", "ssn")
            
            sensitiveKeys.forEach { key ->
                if (json.has(key)) {
                    json.put(key, "***REDACTED***")
                }
            }
            
            json.toString(2)
        } catch (e: Exception) {
            body.take(1000)
        }
    }

    private fun getStackTraceString(throwable: Throwable): String {
        val sw = StringWriter()
        val pw = PrintWriter(sw)
        throwable.printStackTrace(pw)
        return sw.toString()
    }

    private fun getDeviceInfo(): String {
        return JSONObject().apply {
            put("manufacturer", android.os.Build.MANUFACTURER)
            put("model", android.os.Build.MODEL)
            put("android_version", android.os.Build.VERSION.RELEASE)
            put("sdk_int", android.os.Build.VERSION.SDK_INT)
            put("brand", android.os.Build.BRAND)
        }.toString()
    }

    fun getLogFile(): File = logFile

    fun clearLogs() {
        try {
            logFile.delete()
            Timber.i("Logs cleared")
        } catch (e: Exception) {
            Timber.e(e, "Failed to clear logs")
        }
    }

    fun exportLogs(): String {
        return try {
            logFile.readText()
        } catch (e: Exception) {
            Timber.e(e, "Failed to export logs")
            ""
        }
    }
}

class FileLoggingTree(private val logFile: File) : Timber.Tree() {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.getDefault())

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        try {
            val timestamp = dateFormat.format(Date())
            val priorityStr = when (priority) {
                Log.VERBOSE -> "V"
                Log.DEBUG -> "D"
                Log.INFO -> "I"
                Log.WARN -> "W"
                Log.ERROR -> "E"
                Log.ASSERT -> "A"
                else -> "?"
            }

            val logEntry = StringBuilder()
            logEntry.append("[$timestamp] $priorityStr/${tag ?: "Unknown"}: $message\n")

            if (t != null) {
                val sw = StringWriter()
                val pw = PrintWriter(sw)
                t.printStackTrace(pw)
                logEntry.append("${sw}\n")
            }

            synchronized(this) {
                FileWriter(logFile, true).use { writer ->
                    writer.append(logEntry.toString())
                }
            }
        } catch (e: Exception) {
            Log.e("FileLoggingTree", "Failed to write log", e)
        }
    }
}

